for i, s in enumerate(train_samples):
    inp = np.array(s['input'])
    out = np.array(s['output'])
    H, W = inp.shape

    print(f"Example {i}:")

    # Find 7-triplet centers (odd rows)
    triplet_centers = {}
    for r in range(H):
        centers = []
        for c in range(1, W-1):
            if inp[r,c] == 7 and inp[r,c-1] == 7 and inp[r,c+1] == 7:
                # Check it's the middle of a 3-triplet
                if (c >= 2 and inp[r,c-2] == 7):
                    continue  # not the center
                centers.append(c)
        if centers:
            triplet_centers[r] = centers

    # Actually let me find triplets differently - find contiguous 7 blocks
    for r in range(H):
        row = inp[r].tolist()
        blocks = []
        j = 0
        while j < W:
            if row[j] == 7:
                start = j
                while j < W and row[j] == 7:
                    j += 1
                blocks.append((start, j-1, (start+j-1)//2))
            else:
                j += 1
        if blocks:
            centers = [b[2] for b in blocks]
            triplet_centers[r] = centers
            print(f"  Row {r}: 7-blocks at {blocks}, centers at {centers}")

    # Now check: in even rows of output, where are the 6s?
    for r in range(H):
        if r not in triplet_centers:
            sixes = [c for c in range(W) if out[r,c] == 6]
